BlockListener = {}

local didntMovePos = true
local canPutTower = true
local timerKey = nil
local isKeepPressing = false
function BlockListener:init()
    Listener.registerCallBack(BlockStartBreakEvent, BlockListener.onBlockStartBreak)
    Listener.registerCallBack(BlockAbortBreakEvent, BlockListener.onBolckAbortBreak)
end

function BlockListener.onBlockStartBreak(rakssid, blockId, pos)
    if didntMovePos then
        canPutTower = true
    else
        canPutTower = false
    end
    return false              --服务器不接收相关消息（客户端不发送）
end

function BlockListener.onBolckAbortBreak(rakssid, blockId, pos)
    didntMovePos = false
    LuaTimer:scheduleTimer(function()
        if canPutTower then
            EntityListener.onClickToBlock(pos)
        end
    end, 0, 1)
    if timerKey ~= nil then
        LuaTimer:cancel(timerKey)
    end
    timerKey = LuaTimer:scheduleTimer(function () didntMovePos = true timerKey = nil end, 300, 1)
    return false
end

return BlockListener